/// Calcula el factorial de un número de forma recursiva.
/// Devuelve Ok(n!) si n >= 0, o Err con un mensaje si n < 0.
fn factorial(n: i64) -> Result<u64, String> {
    if n < 0 {
        return Err("Factorial is not defined for negative numbers".to_string());
    }
    match n {
        0 => Ok(1),
        _ => Ok(n as u64 * factorial(n - 1)?),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_factorial_zero() {
        assert_eq!(factorial(0), Ok(1));
    }

    #[test]
    fn test_factorial_positive() {
        assert_eq!(factorial(5), Ok(120));
        assert_eq!(factorial(10), Ok(3628800));
    }

    #[test]
    fn test_factorial_negative() {
        assert!(factorial(-1).is_err());
        assert!(factorial(-5).is_err());
    }
}
